.dark {
  /* === Dark OLED Theme === */
  /* Pure black background for OLED pixel-off power saving */
  --background: oklch(0 0 0);
  --foreground: oklch(0.98 0 0);
  /* Subtle elevation: only slightly above black to give depth on OLED */
  --card: oklch(0.14 0 0);
  --card-foreground: oklch(0.98 0 0);
  --popover: oklch(0.14 0 0);
  --popover-foreground: oklch(0.98 0 0);
  /* Primary: near-white for minimal OLED look (low burn-in risk) */
  --primary: oklch(0.98 0 0);
  --primary-foreground: oklch(0 0 0);
  --secondary: oklch(0.18 0 0);
  --secondary-foreground: oklch(0.98 0 0);
  --muted: oklch(0.16 0 0);
  --muted-foreground: oklch(0.65 0 0);
  --accent: oklch(0.2 0 0);
  --accent-foreground: oklch(0.98 0 0);
  --destructive: oklch(0.55 0.2 25);
  /* Very subtle white borders (8% opacity) */
  --border: oklch(1 0 0 / 8%);
  --input: oklch(1 0 0 / 10%);
  --ring: oklch(0.4 0 0);
  /* Desaturated chart colors for OLED */
  --chart-1: oklch(0.6 0.15 250);
  --chart-2: oklch(0.65 0.12 180);
  --chart-3: oklch(0.65 0.14 90);
  --chart-4: oklch(0.6 0.15 310);
  --chart-5: oklch(0.6 0.18 20);
  --sidebar: oklch(0.08 0 0);
  --sidebar-foreground: oklch(0.98 0 0);
  --sidebar-primary: oklch(0.98 0 0);
  --sidebar-primary-foreground: oklch(0 0 0);
  --sidebar-accent: oklch(0.16 0 0);
  --sidebar-accent-foreground: oklch(0.98 0 0);
  --sidebar-border: oklch(1 0 0 / 8%);
  --sidebar-ring: oklch(0.4 0 0);
}

